var earliestFinishTime = function(landStartTime, landDuration, waterStartTime, waterDuration) {
    let best = Infinity;
    for (let i = 0; i < landStartTime.length; i++) {
        for (let j = 0; j < waterStartTime.length; j++) {
            const lf = landStartTime[i] + landDuration[i];
            const a = Math.max(lf, waterStartTime[j]) + waterDuration[j];
            const wf = waterStartTime[j] + waterDuration[j];
            const b = Math.max(wf, landStartTime[i]) + landDuration[i];
            best = Math.min(best, a, b);
        }
    }
    return best;
};
